// claim-office.spec.ts
import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Quote: empty and single base items ---
  it.todo("should return premium of 5 G for empty item list (processing fee only)");
  it.todo("should quote a sword at 100 base + 10 first insurance + 5 fee = 115 G for newcomer");
  it.todo("should quote an amulet at 60 + 6 + 5 = 71 G for newcomer");
  it.todo("should quote a staff at 80 + 8 + 5 = 93 G for newcomer");
  it.todo("should quote a potion at 40 + 4 + 5 = 49 G for newcomer");
  it.todo("should quote a single component (rune) at 25 + 3 + 5 = 33 G (round up) for newcomer");
  it.todo("should quote a single moonstone at 25 + 3 + 5 = 33 G for newcomer");

  // --- Quote: multiple items ---
  it.todo("should sum base premiums for two distinct items");
  it.todo("should sum base premiums for multiple distinct items");

  // --- Quote: components block rule ---
  it.todo("should price 3 alike components as a 60 G block instead of 3 x 25 G");
  it.todo("should not apply block rule to 2 alike components");
  it.todo("should not apply block rule to 4 alike components (only exact 3)");
  it.todo("should not mix component types when forming a block of 3");

  // --- Quote: per-item surcharges ---
  it.todo("should apply +50% cursed surcharge to a cursed sword's base premium");
  it.todo("should apply +30% high-enchantment surcharge for enchantment >= 5");
  it.todo("should not apply high-enchantment surcharge for enchantment < 5");
  it.todo("should apply both cursed and high-enchantment surcharges to the same item");

  // --- Quote: policy-level modifiers ---
  it.todo("should apply +10% first-insurance surcharge per item for a newcomer");
  it.todo("should apply -20% loyalty discount when customer has >= 2 years with MHPCO");
  it.todo("should not apply loyalty discount when customer has < 2 years with MHPCO");
  it.todo("should apply -15% follow-up discount on the second quote in a scenario");
  it.todo("should not apply first-insurance surcharge on a follow-up quote");

  // --- Quote: rounding and fee ---
  it.todo("should add the 5 G processing fee at the end of every quote");
  it.todo("should round the final premium up (in MHPCO's favor)");

  // --- Quote: integration examples from spec ---
  it.todo("should quote newcomer cursed steel sword (ench 3) at 165 G");
  it.todo("should quote 3-year customer 2nd contract cursed steel sword (ench 7) at 160 G");

  // --- Claim: payouts ---
  it.todo("should pay out damage minus 100 G deductible for a normal claim");
  it.todo("should reimburse 50% of insurance value for items with enchantment >= 8, then deduct 100 G");
  it.todo("should fully reimburse insurance value for dragon-material items, then deduct 100 G");
  it.todo("should apply the 50% rule (not full reimbursement) when both high enchantment and dragon material apply");
  it.todo("should round payouts down");
  it.todo("should cap total payouts at 2x the policy's insurance sum");
  it.todo("should report the remaining cap after each claim");

  // --- CLI / scenario errors ---
  it.todo("should error when an unknown item type is quoted");
  it.todo("should error when claiming damage on an item not in the policy");
  it.todo("should error on a negative damage amount");
  it.todo("should error when more damage entries are filed than items of that type in the policy");
});
